    @Override
    public void setAngles(TiansuluoBattleFaceEntity entity, float limbAngle, float limbDistance, float animationProgress, float headYaw, float headPitch) {
        float footRoll = MathHelper.sin(limbAngle * 1.5707964F) * 0.34906584F * limbDistance;
        this.footLeft.roll = footRoll;
        this.footRight.roll = -footRoll;
        this.body.roll = 0.0F;
    }

    @Override
    public void render(MatrixStack matrices, VertexConsumer vertices, int light, int overlay, int color) {
        this.root.render(matrices, vertices, light, overlay, color);
    }
